import{_ as o,o as i,c as n,a2 as a}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Epic: Plugin — Launcher","description":"","frontmatter":{},"headers":[],"relativePath":"epics/plugin-launcher.md","filePath":"epics/plugin-launcher.md"}'),l={name:"epics/plugin-launcher.md"};function t(c,e,r,s,d,u){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="epic-plugin-—-launcher" tabindex="-1">Epic: Plugin — Launcher <a class="header-anchor" href="#epic-plugin-—-launcher" aria-label="Permalink to &quot;Epic: Plugin — Launcher&quot;">​</a></h1><blockquote><p>The home screen — a responsive plugin grid that serves as the default root page at <code>/</code>.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>✅ Complete</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Launcher (<code>fs.sovereign.launcher</code>) is a <code>type: platform</code>, <code>shell: default</code> plugin that renders a tile grid of all installed, enabled, non-chrome plugins. It is the default <code>root_plugin_id</code> — navigating to <code>/</code> loads it via the root-plugin rewrite in runtime middleware. Admin users see a separate &quot;Admin&quot; section for <code>adminOnly: true</code> plugins. Tiles show plugin icon, name, and description; clicking navigates to the plugin&#39;s <code>routePrefix</code>. The Launcher reads its plugin list from a session-gated runtime API (<code>/api/plugins</code>) rather than importing the registry directly — enforcing the SDK boundary.</p><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../plugins/">docs/plugins/launcher.md</a> (plugin spec)</li><li><a href="./../plugin-development.html">plugin-development.md</a></li></ul><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-15-1-—-launcher-plugin" tabindex="-1">✅ 15.1 — Launcher plugin <a class="header-anchor" href="#✅-15-1-—-launcher-plugin" aria-label="Permalink to &quot;✅ 15.1 — Launcher plugin&quot;">​</a></h4><p><strong>Goal:</strong> Platform home screen that lists all installed plugins, serving as the default root page at <code>/</code>.</p><p><strong>Deliverables:</strong></p><ul><li><code>plugins/launcher/</code> with: <ul><li><code>manifest.json</code> — id: <code>fs.sovereign.launcher</code>, type: <code>platform</code>, runtime: <code>native</code>, routePrefix: <code>/launcher</code>, shell: <code>default</code>, icon: <code>icon.svg</code>, permissions: <code>[&quot;auth:session&quot;, &quot;db:readOnly&quot;]</code>, minPlatformVersion: <code>0.4.0</code></li><li><code>icon.svg</code> — grid-of-dots or home symbol</li><li><code>app/page.tsx</code> — plugin grid: reads installed, enabled plugins from registry; excludes chrome plugins (<code>fs.sovereign.launcher</code>, <code>fs.sovereign.account</code>, <code>fs.sovereign.console</code>); renders main grid for accessible plugins; renders a separate &quot;Admin&quot; section for <code>adminOnly: true</code> plugins (visible to <code>platform:admin</code> only); empty state when no non-chrome plugins are installed</li><li><code>components/PluginGrid.tsx</code> — responsive grid layout</li><li><code>components/PluginTile.tsx</code> — tile card: plugin icon + name + description; clicking navigates to the plugin&#39;s <code>routePrefix</code></li></ul></li></ul><p><strong>Dependencies:</strong> Task 0.4.03 (plugin registry and <code>plugin_status</code> table), Task 0.4.04 (root plugin redirect so <code>/</code> loads Launcher by default)</p><p><strong>SRS reference:</strong> LCH-01–LCH-05, PLT-12, <code>docs/plugins/launcher.md</code></p><p><strong>Review checklist:</strong></p><ul><li>Navigating to <code>/</code> loads the Launcher page (via the root plugin redirect set in Task 0.4.04)</li><li>All installed, enabled, non-chrome plugins appear as tiles with icon, name, and description</li><li><code>adminOnly</code> plugins appear only in the Admin section and only for <code>platform:admin</code> users</li><li>Chrome plugins (<code>fs.sovereign.launcher</code>, <code>fs.sovereign.account</code>, <code>fs.sovereign.console</code>) do not appear in any tile section</li><li>Clicking a tile navigates to the plugin&#39;s <code>routePrefix</code></li><li>Empty state is shown when no non-chrome plugins are installed</li><li><code>pnpm lint</code>, <code>pnpm format:check</code>, and <code>pnpm typecheck</code> pass</li></ul><hr>',18)])])}const g=o(l,[["render",t]]);export{h as __pageData,g as default};
